import streamlit as st


def ai_card(message=None, recommendation="Complete today’s workout and log every set", protein_status="On Track", hydration_status="Below Goal"):
    html = f'<div style="background:linear-gradient(145deg,rgba(16,38,63,0.98),rgba(10,23,40,0.95));border:1px solid rgba(255,255,255,0.1);border-radius:24px;padding:24px;margin-bottom:20px"><div style="display:flex;align-items:center;gap:10px;margin-bottom:12px"><div style="width:38px;height:38px;border-radius:999px;background:rgba(255,255,255,0.1);display:flex;align-items:center;justify-content:center;color:#8B5CF6;font-weight:800">🤖</div><div style="font-size:1.15rem;font-weight:800;color:white">AI Daily Briefing</div></div><div style="color:#dbeafe;font-size:1rem;line-height:1.7;display:grid;gap:10px"><div style="font-size:1rem;line-height:1.7;color:#e2e8f0">{message or "Recovery looks excellent. Keep your form clean, protect the knee, and finish the session with a strong note."}</div><div style="display:flex;flex-wrap:wrap;gap:10px;margin-top:6px"><span style="padding:8px 11px;border-radius:999px;background:rgba(34,197,94,0.12);border:1px solid rgba(34,197,94,0.35);color:#dcfce7;font-weight:800">Recommendation • {recommendation}</span><span style="padding:8px 11px;border-radius:999px;background:rgba(59,130,246,0.12);border:1px solid rgba(59,130,246,0.35);color:#dbeafe;font-weight:800">Protein • {protein_status}</span><span style="padding:8px 11px;border-radius:999px;background:rgba(245,158,11,0.12);border:1px solid rgba(245,158,11,0.35);color:#fde68a;font-weight:800">Hydration • {hydration_status}</span></div></div></div>'
    st.markdown(html, unsafe_allow_html=True)
